# Урок 17: Декораторы
# @wraps, *args, **kwargs

from functools import wraps

# 1. Простой декоратор
def simple_decorator(func):
    def wrapper():
        print("ДО вызова функции")
        func()
        print("ПОСЛЕ вызова функции")
    return wrapper

@simple_decorator
def say_hello():
    print("Привет!")

print("Простой декоратор:")
say_hello()

# 2. Декоратор с аргументами
def log_calls(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"[LOG] Вызов {func.__name__}")
        result = func(*args, **kwargs)
        print(f"[LOG] Результат: {result}")
        return result
    return wrapper

@log_calls
def add(a, b):
    return a + b

print("\nДекоратор логирования:")
print(add(10, 5))
print(add(20, 30))

# 3. Декоратор с параметром
def repeat(times):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            for i in range(times):
                result = func(*args, **kwargs)
            return result
        return wrapper
    return decorator

@repeat(3)
def greet(name):
    print(f"Привет, {name}!")

print("\nДекоратор повторения:")
greet("Анна")

# 4. Цепочка декораторов
def bold(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return f"<b>{func(*args, **kwargs)}</b>"
    return wrapper

def italic(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return f"<i>{func(*args, **kwargs)}</i>"
    return wrapper

@bold
@italic
def get_name():
    return "Python"

print(f"\nЦепочка декораторов: {get_name()}")

